class Solution {
    public int maxSatisfied(int[] customers, int[] grumpy, int minutes) {
        int n = customers.length;
        int total = 0;
        for (int i = 0; i < n; i++) {
            if (grumpy[i] == 0) {
                total += customers[i];
            }
        }
        int maxIncrease = 0;
        int windowSum = 0;
        for (int i = 0; i < minutes; i++) {
            windowSum += customers[i] * grumpy[i];
        }
        maxIncrease = windowSum;
        for (int i = minutes; i < n; i++) {
            windowSum = windowSum - customers[i - minutes] * grumpy[i - minutes] + customers[i] * grumpy[i];
            maxIncrease = Math.max(maxIncrease, windowSum);
        }
        return total + maxIncrease;
    }
}
